// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{})
}

// ServeMux is an abstraction of [http.ServeMux].
type ServeMux interface {
	HandleFunc(pattern string, handler func(http.ResponseWriter, *http.Request))
	http.Handler
}

type StdHTTPServerOptions struct {
	BaseURL          string
	BaseRouter       ServeMux
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, m ServeMux) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseRouter: m,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, m ServeMux, baseURL string) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseURL:    baseURL,
		BaseRouter: m,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options StdHTTPServerOptions) http.Handler {
	m := options.BaseRouter

	if m == nil {
		m = http.NewServeMux()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/announce", wrapper.PostAnnounce)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/backfill", wrapper.PostBackfill)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/check", wrapper.GetCheck)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/listen", wrapper.PostListen)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/notify", wrapper.PostNotify)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/register", wrapper.PostRegister)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/release", wrapper.PostRelease)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/resolve", wrapper.GetResolve)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/send", wrapper.PostSend)
	m.HandleFunc(http.MethodDelete+" "+options.BaseURL+"/api/session/{callsign}", wrapper.DeleteSession)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/sessions", wrapper.GetSessions)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/sessions/bash-dump", wrapper.GetSessionsBashDump)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/sessions/edit", wrapper.PostEditSession)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/sessions/export", wrapper.PostSessionsExport)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/sessions/find", wrapper.GetSessionsFind)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/sessions/heatmap", wrapper.GetSessionsHeatmap)
	m.HandleFunc(http.MethodDelete+" "+options.BaseURL+"/api/sessions/{identifier}", wrapper.DeleteSessionById)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/sessions/{identifier}/detail", wrapper.GetSessionDetail)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/sessions/{identifier}/export", wrapper.PostSessionExport)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/sessions/{identifier}/messages", wrapper.GetSessionMessages)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/sessions/{identifier}/peek", wrapper.GetSessionPeek)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/sessions/{identifier}/pulse", wrapper.PostSessionPulse)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/sessions/{identifier}/tool-context", wrapper.GetSessionToolContext)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/sessions/{identifier}/tools", wrapper.GetSessionTools)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/sweep", wrapper.PostSweep)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/timeline", wrapper.GetTimeline)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/usage", wrapper.GetUsage)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/wait", wrapper.GetWait)

	return m
}

